package javaday10;

public class weekdaysusingname {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		String weekname="monday";
		
		switch(weekname)
		{
			case "sunday":System.out.println(1);
			              break;
			              
			case "monday":System.out.println(2);
                          break;
            
			case "tuesday":System.out.println(3);
                           break;
            
			case "wedesday":System.out.println(4);
                            break;
            
			case "thusday":System.out.println(5);
                           break;
            
			case "friday":System.out.println(6);
                          break;
            
			case "satureday":System.out.println(7);
                             break;
            
            default :System.out.println("invalid number");
		}

	}

}
